def search_contains(term, fields=('hadithTxt','Matn'), limit=20):
    nt = normalize_arabic(term)
    res = []
    for h in hadith_data:
        for field in fields:
            text = h.get(field) or ''
            if not text:
                continue
            if nt in normalize_arabic(text):
                res.append((h['hadithID'], field, text))
                break
    return res[:limit]

