def search_tokens(tokens):
    res=[]
    for h in hadith_data:
        text = (h.get('Matn') or '') + " " + (h.get('hadithTxt') or '')
        nt = normalize_arabic(text)
        ok=True
        for tok in tokens:
            if tok not in nt:
                ok=False
                break
        if ok:
            res.append((h['hadithID'], h.get('Matn') or h.get('hadithTxt')))
    return res

